            '/w': { desc: 'Shortcut for /who', fn: () => this.cmdWho() },
            '/clear': { desc: 'Clear chat messages', fn: () => this.cmdClear() },
            '/block': { desc: 'Block a user or #channel', fn: (args) => this.cmdBlock(args) },
